import { useContext } from "react";
import { Table, Container, Card } from "react-bootstrap";
import UserContext from "./context";

export default function TransactionHistory() {
    const { user } = useContext(UserContext);

    if (!user) return <Container className="mt-5"><h3>Please login to view your transaction history.</h3></Container>;

    return (
        <Container className="mt-5">
            <Card className="shadow">
                <Card.Header className="bg-dark text-white">
                    <h2 className="mb-0">Money Tracking - History</h2>
                </Card.Header>
                <Card.Body>
                    <div className="text-end mb-3">
                        <h4 className="text-primary">Current Balance: ₹{user.amount}</h4>
                    </div>
                    <Table striped bordered hover responsive>
                        <thead className="table-dark">
                            <tr>
                                <th>#</th>
                                <th>Type</th>
                                <th>Amount</th>
                                <th>Date & Time</th>
                            </tr>
                        </thead>
                        <tbody>
                            {user.transactions && user.transactions.length > 0 ? (
                                user.transactions.slice().reverse().map((tx, index) => (
                                    <tr key={index}>
                                        <td>{user.transactions.length - index}</td>
                                        <td className={tx.type === 'deposit' ? 'text-success fw-bold' : 'text-danger fw-bold'}>
                                            {tx.type.toUpperCase()}
                                        </td>
                                        <td>₹{tx.amount}</td>
                                        <td>{new Date(tx.date).toLocaleString()}</td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan="4" className="text-center">No transactions found.</td>
                                </tr>
                            )}
                        </tbody>
                    </Table>
                </Card.Body>
            </Card>
        </Container>
    );
}
